it("should bring a dead cell with exactly 3 live neighbors to life (reproduction)", () => {
  // Gen 0:        Gen 1:
  //  ##.           ##.
  //  #..     →     ##.
  //  ...           ...
  // Dead cell (1,1) has exactly 3 live neighbors: (0,0),(1,0),(0,1)
  expect(
    nextGeneration([
      [0, 0],
      [1, 0],
      [0, 1],
    ]),
  ).toContainEqual([1, 1]);
